var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"살아남은 반군들은 꽁무니 빼고 있어, 누님.","JPN":"反乱軍の生き残りは逃げているよ、姉さん。","ENG":"The remaining rebel forces are retreating, Ma'am.","TWN":"報告姊，倖存的叛軍逃逸中，"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"일단 고용된 입장으로서 묻는데, 추격할 건가?","JPN":"雇われているから一応聞くが、追うつもりか？","ENG":"I’m asking this as a hired gun but, shall we give chase?","TWN":"基於受雇的立場，我還是必須禮貌性地問一下，要追嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"마음은 굴뚝 같지만……. 아니.","JPN":"そうしたい気持ちは山々だけど……やめとく。","ENG":"I want to with all my heart but... No.","TWN":"我是很想追……但不行！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"파레마는 아직 저들이 장악하고 있어. 함부로 따라 들어갔다간 험한 꼴 보게 돼.","JPN":"パレマはまだ彼らが掌握している。むやみについて行ったらひどい目に遭う。","ENG":"Parema is still under their control. If we give chase, things will get ugly fast.","TWN":"波雷馬還在他們的掌握之下，一時衝動追上去恐怕會有危險。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"하하. 지휘도 잘하더니 판단도 상식적이라 다행이군.","JPN":"はは。指揮が上手いと思ったら、判断も常識的でよかった。","ENG":"Ha ha. It’s nice to work for someone with common sense.","TWN":"哈哈，還好你不只有領導力，判斷力也不差！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"아까 바이크로 유인해 오는 솜씨가 대단하던데, 혹시 선수 출신이야?","JPN":"さっきバイクで誘導するところが上手かったが、もしかして選手出身か？","ENG":"Back there, your skill with the motorcycle was incredible. Did you use to be a professional?","TWN":"我看你剛才騎摩托車的樣子，好像很厲害，你是賽車選手嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"선수라니 과찬이네. 여기저기 다니느라 손에 익은 정도야.","JPN":"選手なんて言いすぎよ。よく乗ってたから慣れただけ。","ENG":"How nice of you to say that. But, no, I’ve just had some practice here and there.","TWN":"沒這麼誇張啦，還賽車選手咧，只是我常常騎車到處跑，所以比較熟練而已。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"아, 그거 혹시 작업 멘트였어?","JPN":"あ、もしかしてそれナンパだった？","ENG":"Ah, was that a pick-up line?","TWN":"喔！你這是在跟我搭訕嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"영업도 겸해야 하는 프리랜서의 아부성 멘트라고 생각해.","JPN":"営業も必要なフリーランサーのお世辞だと思えばいい。","ENG":"Rather take it as a compliment from a freelancer that has to make sales.","TWN":"應該說是以利益為出發點的搭訕。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"우리 업계에선 그로니아 보안국 인간들과는 같은 카페도 다니지 말라고 하거든.","JPN":"こちらの業界ではグロニア保安局のやつらとは同じカフェにも入るなって言ってるからな。","ENG":"You know, people in my line of work try to avoid even being in the same building as people from the Gronia National Security.","TWN":"否則在我們業界都說，連和格羅尼亞安全局的人一起喝咖啡都最好不要呢！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"역시 용병 분들이 냄새를 잘 맡아.","JPN":"やっぱり、傭兵は勘がいいね。","ENG":"Ha, then people in your line of work have good sense.","TWN":"傭兵果然很敏銳呢！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"심문할 상대가 있어서 먼저 실례할게. 추가 수당은 내 상관에게 요구하면 돼.","JPN":"尋問する相手がいるからお先に失礼するわ。追加手当は私の上官に請求して。","ENG":"Please excuse me, I have to interrogate someone. I’ll take my leave. You may ask my boss for the bonus pay.","TWN":"我還想找個人問話，就先走一步，額外的費用可以找我的長官申請。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"계산이 깔끔해서 좋군. 종종 애용해 달라고.","JPN":"潔くていい。また呼んでくれよ。","ENG":"Wow, a bonus even? Please. Feel free to request for us anytime.","TWN":"這樣算得清清楚楚，真好！希望以後還有合作機會！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"크윽…… 허억…… 허억…….","JPN":"くうっ……はあ……はあ……","ENG":"Argh... *Huff… Huff...*","TWN":"咳……咳咳……呃……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"급소도 아닌 곳에 총알 몇 발 맞았다고 엄살 부리지 마, 쓰레기.","JPN":"急所でもないところに何発か当たったからって泣き言言うな、くず。","ENG":"Oh please, don’t be so dramatic. None of your vitals were hit, scum.","TWN":"我根本沒打中你的要害，少在那邊給我裝模作樣的，垃圾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"크흐…… 흐…… 흐흐…….","JPN":"くふ……ふ……ふふ……","ENG":"Hrgh... Ha... Haah...","TWN":"咳咳……呃……呼呼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"너, 보안국 소속이지. 그 썩은 눈빛을 보니 알겠군.","JPN":"お前、保安局のやつだな。その腐った目を見ればわかる。","ENG":"Clearly you’re a member of the National Security. I can tell by that disgusting look in your eye.","TWN":"看你那腐敗的眼神就知道，你是安全局的吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"우리 대장님은…… 사생활은 지저분해도 선은 지키는 분이었어.","JPN":"俺らの隊長は……汚いとこもあったが、一線は超えない方だった。","ENG":"My Captain... Sure his personal life might have been a bit messy, but he was a good man.","TWN":"我們隊長……雖然私生活不檢點，但他的心地很善良。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};